[ApiController]
[Route("api/v1/[controller]")]
[Authorize]
public class UsersController : ControllerBase
{
    private readonly IUserService _userService;
    private readonly ILogger<UsersController> _logger;

    public UsersController(IUserService userService, ILogger<UsersController> logger)
    {
        _userService = userService;
        _logger = logger;
    }

    [HttpGet]
    public async Task<ActionResult<PagedResult<UserDto>>> GetUsers(
        [FromQuery] int page = 1,
        [FromQuery] int pageSize = 20,
        CancellationToken ct = default)
    {
        return Ok(await _userService.GetAllAsync(page, pageSize, ct));
    }

    [HttpPost]
    public async Task<ActionResult<UserDto>> CreateUser(
        CreateUserDto dto, CancellationToken ct)
    {
        var user = await _userService.CreateAsync(dto, ct);
        return CreatedAtAction(nameof(GetUsers), new { id = user.Id }, user);
    }
}

public class UserService : IUserService
{
    private readonly AppDbContext _db;
    private readonly IMapper _mapper;
    private readonly TimeProvider _time;

    public UserService(AppDbContext db, IMapper mapper, TimeProvider time)
    {
        _db = db;
        _mapper = mapper;
        _time = time;
    }

    public async Task<UserDto> CreateAsync(CreateUserDto dto, CancellationToken ct)
    {
        var user = _mapper.Map<User>(dto);
        user.CreatedAt = _time.GetUtcNow();
        _db.Users.Add(user);
        await _db.SaveChangesAsync(ct);
        return _mapper.Map<UserDto>(user);
    }
}

public class ProblemDetailsHandler : IExceptionHandler
{
    public async ValueTask<bool> TryHandleAsync(
        HttpContext ctx, Exception ex, CancellationToken ct)
    {
        var pd = ex switch
        {
            NotFoundException nf =>
                new ProblemDetails { Status = 404, Title = nf.Message },
            ValidationException ve =>
                new ProblemDetails { Status = 422, Title = "Validation failed",
                                     Detail = ve.Message },
            _ => new ProblemDetails { Status = 500, Title = "Server error" }
        };
        ctx.Response.StatusCode = pd.Status!.Value;
        await ctx.Response.WriteAsJsonAsync(pd, ct);
        return true;
    }
}

